    def getBalance(ctx, account_id):
        """
        Retrieve the current balance for a given account.
        SOAPAction: urn:financial.services/getBalance
        """
        logger.info("getBalance called for account: %s", account_id)

        response = BalanceResponse()
        response.as_of = datetime.utcnow()

        if not account_id:
            response.status_code = 400
            response.status_message = "Account ID is required."
            return response

        account = ACCOUNTS_DB.get(account_id)
        if account is None:
            response.status_code = 404
            response.status_message = f"Account '{account_id}' not found."
            return response

        if not account["is_active"]:
            response.account_id = account_id
            response.balance = account["balance"]
            response.currency = account["currency"]
            response.status_code = 403
            response.status_message = "Account is inactive. Balance shown but operations are restricted."
            return response

        response.account_id = account_id
        response.balance = account["balance"]
        response.currency = account["currency"]
        response.status_code = 200
        response.status_message = "Success"
